"""
BioCompiler Retrospective Validation — Successful Gene Designs
================================================================
Tests that known successful gene designs pass BioCompiler predicate checks.

This is the positive half of retrospective validation: real genes that are
known to express correctly should pass the relevant type-system predicates.
Any unexpected failure (false positive) is documented and the false positive
rate is asserted to be < 20%.

Gene designs included (17 total):
  1.  E. coli codon-optimized GFP (common expression construct)
  2.  E. coli codon-optimized mCherry (fluorescent reporter)
  3.  E. coli thioredoxin (native, well-expressed)
  4.  Human growth hormone (therapeutic, well-characterized)
  5.  E. coli MBP — maltose binding protein (highly soluble)
  6.  Human serum albumin fragment (highly expressed plasma protein)
  7.  PETase (engineered enzyme for PET degradation)
  8.  Cas9 fragment (CRISPR nuclease, widely used)
  9.  Insulin A chain (therapeutic)
 10.  Insulin B chain (therapeutic)
 11.  IL-2 — interleukin-2 (therapeutic cytokine)
 12.  E. coli GroEL fragment (chaperonin, well-expressed)
 13.  Taq polymerase fragment (thermostable enzyme)
 14.  Beta-lactamase (common selection marker)
 15.  Lysozyme (well-studied small enzyme)
 16.  SUMO tag (solubility enhancer)
 17.  Nanobody VHH (small, soluble, stable)

All sequences are E. coli codon-optimized using preferred codons from the
Kazusa Codon Database (K-12 MG1655, high-expression genes).
"""

import pytest
from typing import Dict, List, Tuple

from biocompiler.type_system import (
    check_no_stop_codons,
    check_valid_coding_seq,
    check_no_gt_dinucleotide,
    check_no_avoidable_gt,
    check_no_cpg_island,
    check_no_cryptic_splice,
    check_no_cryptic_promoter,
    check_no_unexpected_tm_domain,
    check_mrna_secondary_structure,
    check_codon_optimality,
    check_no_restriction_site,
    check_co_translational_folding,
    CODON_TABLE,
    AA_TO_CODONS,
)
from biocompiler.types import Verdict
from biocompiler.organisms.e_coli import E_COLI_CODON_ADAPTIVENESS


# ────────────────────────────────────────────────────────────
# Helper: translate DNA to protein
# ────────────────────────────────────────────────────────────
def _translate(seq: str) -> str:
    """Translate a DNA coding sequence to amino acids."""
    protein = []
    for i in range(0, len(seq), 3):
        codon = seq[i:i + 3]
        aa = CODON_TABLE.get(codon, "X")
        if aa == "*":
            break
        protein.append(aa)
    return "".join(protein)


# ────────────────────────────────────────────────────────────
# Helper: E. coli CAI dictionary
# ────────────────────────────────────────────────────────────
E_COLI_CAI: Dict[str, float] = E_COLI_CODON_ADAPTIVENESS


