# ────────────────────────────────────────────────────────────
# Test class: Retrospective successful design validation
# ────────────────────────────────────────────────────────────

class TestRetrospectiveSuccessfulDesigns:
    """Verify that known successful gene designs pass BioCompiler predicates."""

    # ---- DNA-level predicate runners ----

    @staticmethod
    def _run_no_stop_codons(seq: str) -> bool:
        result = check_no_stop_codons(seq)
        return result.passed

    @staticmethod
    def _run_valid_coding_seq(seq: str) -> bool:
        result = check_valid_coding_seq(seq)
        return result.passed

    @staticmethod
    def _run_no_cpg_island(seq: str) -> bool:
        result = check_no_cpg_island(seq)
        return result.passed

    @staticmethod
    def _run_no_cryptic_splice(seq: str) -> bool:
        result = check_no_cryptic_splice(seq)
        return result.passed

    @staticmethod
    def _run_no_cryptic_promoter(seq: str) -> bool:
        result = check_no_cryptic_promoter(seq, organism="E_coli")
        return result.passed

    @staticmethod
    def _run_no_unexpected_tm_domain(seq: str) -> bool:
        result = check_no_unexpected_tm_domain(seq, is_cytosolic=True)
        return result.passed

    @staticmethod
    def _run_mrna_secondary_structure(seq: str) -> bool:
        result = check_mrna_secondary_structure(seq)
        return result.passed

    @staticmethod
    def _run_codon_optimality(seq: str) -> bool:
        """Check codon optimality: all codons should have CAI >= 0.2."""
        all_pass = True
        for i in range(0, len(seq), 3):
            codon = seq[i:i + 3]
            if codon in CODON_TABLE and CODON_TABLE[codon] != "*":
                result = check_codon_optimality(codon, E_COLI_CAI, min_cai=0.2)
                if not result.passed:
                    all_pass = False
        return all_pass

    @staticmethod
    def _run_no_restriction_site(seq: str) -> bool:
        """Check for common cloning restriction sites."""
        common_enzymes = ["EcoRI", "BamHI", "XhoI", "HindIII", "NotI", "NdeI", "NcoI"]
        result = check_no_restriction_site(seq, common_enzymes)
        return result.passed

    @staticmethod
    def _run_no_avoidable_gt(seq: str) -> bool:
        result = check_no_avoidable_gt(seq)
        return result.passed

    @staticmethod
    def _run_co_translational_folding(seq: str) -> bool:
        result = check_co_translational_folding(seq, E_COLI_CAI)
        return result.passed

    @staticmethod
    def _run_stable_folding(seq: str) -> bool:
        """Check stability predicate (sequence-based heuristic)."""
        from biocompiler.stability_predicates import evaluate_stable_folding
        protein = _translate(seq)
        result = evaluate_stable_folding(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_disulfide_bond_integrity(seq: str) -> bool:
        """Check disulfide bond integrity."""
        from biocompiler.stability_predicates import evaluate_disulfide_bond_integrity
        protein = _translate(seq)
        result = evaluate_disulfide_bond_integrity(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_hydrophobic_core_quality(seq: str) -> bool:
        """Check hydrophobic core quality."""
        from biocompiler.stability_predicates import evaluate_hydrophobic_core_quality
        protein = _translate(seq)
        result = evaluate_hydrophobic_core_quality(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_soluble_expression(seq: str) -> bool:
        """Check soluble expression prediction."""
        from biocompiler.solubility_predicates import evaluate_soluble_expression
        protein = _translate(seq)
        result = evaluate_soluble_expression(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_no_aggregation_prone_region(seq: str) -> bool:
        """Check for aggregation-prone regions."""
        from biocompiler.solubility_predicates import evaluate_no_aggregation_prone_region
        protein = _translate(seq)
        result = evaluate_no_aggregation_prone_region(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_charge_composition(seq: str) -> bool:
        """Check charge composition."""
        from biocompiler.solubility_predicates import evaluate_charge_composition
        protein = _translate(seq)
        result = evaluate_charge_composition(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_no_long_hydrophobic_stretch(seq: str) -> bool:
        """Check for long hydrophobic stretches."""
        from biocompiler.solubility_predicates import evaluate_no_long_hydrophobic_stretch
        protein = _translate(seq)
        result = evaluate_no_long_hydrophobic_stretch(seq, protein, "E_coli")
        return result.passed

    @staticmethod
    def _run_no_destabilizing_mutation(seq: str) -> bool:
        """No original protein → PASS by definition."""
        from biocompiler.stability_predicates import evaluate_no_destabilizing_mutation
        protein = _translate(seq)
        result = evaluate_no_destabilizing_mutation(seq, protein, "E_coli")
        return result.passed

    # Mapping from predicate name to runner function
    PREDICATE_RUNNERS = {
        "NoStopCodons": "_run_no_stop_codons",
        "ValidCodingSeq": "_run_valid_coding_seq",
        "NoCpGIsland": "_run_no_cpg_island",
        "NoCrypticSplice": "_run_no_cryptic_splice",
        "NoCrypticPromoter": "_run_no_cryptic_promoter",
        "NoUnexpectedTMDomain": "_run_no_unexpected_tm_domain",
        "mRNASecondaryStructure": "_run_mrna_secondary_structure",
        "CodonOptimality": "_run_codon_optimality",
        "NoRestrictionSite": "_run_no_restriction_site",
        "NoAvoidableGT": "_run_no_avoidable_gt",
        "CoTranslationalFolding": "_run_co_translational_folding",
        "StableFolding": "_run_stable_folding",
        "DisulfideBondIntegrity": "_run_disulfide_bond_integrity",
        "HydrophobicCoreQuality": "_run_hydrophobic_core_quality",
        "NoDestabilizingMutation": "_run_no_destabilizing_mutation",
        "SolubleExpression": "_run_soluble_expression",
        "NoAggregationProneRegion": "_run_no_aggregation_prone_region",
        "ChargeComposition": "_run_charge_composition",
        "NoLongHydrophobicStretch": "_run_no_long_hydrophobic_stretch",
    }

    def _run_predicate(self, name: str, seq: str) -> bool:
        """Run a named predicate and return whether it passed."""
        runner_name = self.PREDICATE_RUNNERS.get(name)
        if runner_name is None:
            pytest.skip(f"No runner for predicate '{name}'")
        runner = getattr(self, runner_name)
        return runner(seq)

    # ---- Per-design tests ----

    @pytest.mark.parametrize("design_idx", range(len(SUCCESSFUL_DESIGNS)),
                             ids=[d["name"] for d in SUCCESSFUL_DESIGNS])
    def test_design_no_stop_codons(self, design_idx):
        """All successful designs should have no internal stop codons."""
        design = SUCCESSFUL_DESIGNS[design_idx]
        assert self._run_no_stop_codons(design["sequence"]), (
            f"{design['name']}: NoStopCodons should PASS for a valid gene design"
        )

    @pytest.mark.parametrize("design_idx", range(len(SUCCESSFUL_DESIGNS)),
                             ids=[d["name"] for d in SUCCESSFUL_DESIGNS])
    def test_design_valid_coding_seq(self, design_idx):
        """All successful designs should be valid coding sequences."""
        design = SUCCESSFUL_DESIGNS[design_idx]
        assert self._run_valid_coding_seq(design["sequence"]), (
            f"{design['name']}: ValidCodingSeq should PASS for a valid gene design"
        )

    @pytest.mark.parametrize("design_idx", range(len(SUCCESSFUL_DESIGNS)),
                             ids=[d["name"] for d in SUCCESSFUL_DESIGNS])
    def test_design_expected_predicates_pass(self, design_idx):
        """Each design's expected_pass_predicates should actually pass."""
        design = SUCCESSFUL_DESIGNS[design_idx]
        failures = []
        for pred_name in design["expected_pass_predicates"]:
            try:
                passed = self._run_predicate(pred_name, design["sequence"])
                if not passed:
                    failures.append(pred_name)
            except Exception as e:
                failures.append(f"{pred_name}(ERROR: {e})")
        assert not failures, (
            f"{design['name']}: Expected predicates that FAILED: {failures}"
        )

    # ---- Aggregate tests ----

    def test_all_designs_valid_coding(self):
        """ALL designs must be valid coding sequences with no stop codons."""
        for design in SUCCESSFUL_DESIGNS:
            seq = design["sequence"]
            assert len(seq) % 3 == 0, f"{design['name']}: length not divisible by 3"
            assert self._run_valid_coding_seq(seq), f"{design['name']}: not valid coding"
            assert self._run_no_stop_codons(seq), f"{design['name']}: has internal stops"

    def test_pass_rate_on_core_predicates(self):
        """Core predicate pass rate (NoStopCodons + ValidCodingSeq) should be 100%."""
        core_predicates = ["NoStopCodons", "ValidCodingSeq"]
        total_checks = 0
        total_passes = 0

        for design in SUCCESSFUL_DESIGNS:
            for pred_name in core_predicates:
                total_checks += 1
                if self._run_predicate(pred_name, design["sequence"]):
                    total_passes += 1

        pass_rate = total_passes / total_checks if total_checks > 0 else 0.0
        assert pass_rate == 1.0, (
            f"Core predicate pass rate should be 100%, got {pass_rate:.1%} "
            f"({total_passes}/{total_checks})"
        )

    def test_false_positive_rate(self):
        """Calculate false positive rate for expected-pass predicates.

        False positive = a predicate that was expected to pass but actually failed.
        The false positive rate should be < 20%.
        """
        total_expected_pass = 0
        unexpected_failures = 0
        failure_details: List[Tuple[str, str]] = []

        for design in SUCCESSFUL_DESIGNS:
            for pred_name in design["expected_pass_predicates"]:
                total_expected_pass += 1
                try:
                    passed = self._run_predicate(pred_name, design["sequence"])
                    if not passed:
                        unexpected_failures += 1
                        failure_details.append((design["name"], pred_name))
                except Exception as e:
                    unexpected_failures += 1
                    failure_details.append((design["name"], f"{pred_name}(ERROR: {e})"))

        false_positive_rate = (
            unexpected_failures / total_expected_pass if total_expected_pass > 0 else 0.0
        )

        # Print details for debugging
        if failure_details:
            print(f"\nUnexpected failures ({unexpected_failures}/{total_expected_pass}):")
            for name, pred in failure_details:
                print(f"  {name}: {pred}")

        assert false_positive_rate < 0.20, (
            f"False positive rate {false_positive_rate:.1%} exceeds 20% threshold "
            f"({unexpected_failures}/{total_expected_pass} unexpected failures). "
            f"Details: {failure_details}"
        )

    def test_overall_pass_rate(self):
        """Compute and report overall pass rate for ALL predicates across ALL designs.

        This is informational — not a hard threshold, but should be > 50%.
        """
        all_predicates = list(self.PREDICATE_RUNNERS.keys())
        total_checks = 0
        total_passes = 0
        per_predicate_stats: Dict[str, Dict] = {}

        for pred_name in all_predicates:
            per_predicate_stats[pred_name] = {"pass": 0, "fail": 0, "error": 0}

        for design in SUCCESSFUL_DESIGNS:
            for pred_name in all_predicates:
                total_checks += 1
                try:
                    if self._run_predicate(pred_name, design["sequence"]):
                        total_passes += 1
                        per_predicate_stats[pred_name]["pass"] += 1
                    else:
                        per_predicate_stats[pred_name]["fail"] += 1
                except Exception:
                    per_predicate_stats[pred_name]["error"] += 1

        pass_rate = total_passes / total_checks if total_checks > 0 else 0.0

        # Print summary
        print(f"\n{'='*60}")
        print(f"Overall pass rate: {pass_rate:.1%} ({total_passes}/{total_checks})")
        print(f"{'='*60}")
        print(f"{'Predicate':<30} {'Pass':>5} {'Fail':>5} {'Error':>5}")
        print(f"{'-'*60}")
        for pred_name in all_predicates:
            s = per_predicate_stats[pred_name]
            print(f"{pred_name:<30} {s['pass']:>5} {s['fail']:>5} {s['error']:>5}")

        # The pass rate should be reasonable — > 50%
        assert pass_rate > 0.50, (
            f"Overall pass rate {pass_rate:.1%} is below 50% — "
            f"too many predicate failures for known successful designs"
        )

    def test_solubility_predicates_pass_rate(self):
        """Solubility predicates should have reasonable pass rates for well-expressed proteins."""
        solubility_preds = [
            "SolubleExpression",
            "ChargeComposition",
            "NoLongHydrophobicStretch",
        ]
        total = 0
        passes = 0
        for design in SUCCESSFUL_DESIGNS:
            for pred_name in solubility_preds:
                total += 1
                try:
                    if self._run_predicate(pred_name, design["sequence"]):
                        passes += 1
                except Exception:
                    pass
        pass_rate = passes / total if total > 0 else 0.0
        assert pass_rate >= 0.30, (
            f"Solubility pass rate {pass_rate:.1%} is below 30% for known successful designs"
        )

    def test_stability_predicates_pass_rate(self):
        """Stability predicates should have reasonable pass rates for stable proteins."""
        stability_preds = [
            "StableFolding",
            "DisulfideBondIntegrity",
            "HydrophobicCoreQuality",
            "NoDestabilizingMutation",
        ]
        total = 0
        passes = 0
        for design in SUCCESSFUL_DESIGNS:
            for pred_name in stability_preds:
                total += 1
                try:
                    if self._run_predicate(pred_name, design["sequence"]):
                        passes += 1
                except Exception:
                    pass
        pass_rate = passes / total if total > 0 else 0.0
        assert pass_rate >= 0.30, (
            f"Stability pass rate {pass_rate:.1%} is below 30% for known successful designs"
        )

    def test_no_gt_dinucleotide_analysis(self):
        """Analyze GT dinucleotide presence in successful designs.

        Valine codons (GTN) always contain GT, so the strict NoGTDinucleotide
        predicate is expected to fail for most genes. The relaxed NoAvoidableGT
        should have better pass rates.
        """
        strict_pass = 0
        relaxed_pass = 0
        total = len(SUCCESSFUL_DESIGNS)

        for design in SUCCESSFUL_DESIGNS:
            if self._run_no_avoidable_gt(design["sequence"]):
                relaxed_pass += 1
            # Strict GT check — most will fail due to valine
            # Just count, don't assert

        relaxed_rate = relaxed_pass / total if total > 0 else 0.0
        # NoAvoidableGT should pass for most optimized designs
        # (though valine makes this impossible for strict GT)
        print(f"\nNoAvoidableGT pass rate: {relaxed_rate:.1%} ({relaxed_pass}/{total})")

    def test_cryptic_splice_in_prokaryotic_context(self):
        """For E. coli expression, cryptic splice sites are less relevant
        but should still be checked — short constructs should generally pass."""
        pass_count = 0
        for design in SUCCESSFUL_DESIGNS:
            if self._run_no_cryptic_splice(design["sequence"]):
                pass_count += 1
        pass_rate = pass_count / len(SUCCESSFUL_DESIGNS)
        print(f"\nNoCrypticSplice pass rate (prokaryotic): {pass_rate:.1%}")

    def test_cryptic_promoter_in_ecoli_context(self):
        """For E. coli expression, cryptic promoters can cause issues."""
        pass_count = 0
        for design in SUCCESSFUL_DESIGNS:
            if self._run_no_cryptic_promoter(design["sequence"]):
                pass_count += 1
        pass_rate = pass_count / len(SUCCESSFUL_DESIGNS)
        print(f"\nNoCrypticPromoter pass rate (E. coli): {pass_rate:.1%}")

    def test_mrna_secondary_structure_pass_rate(self):
        """mRNA secondary structure around the RBS should generally be acceptable."""
        pass_count = 0
        for design in SUCCESSFUL_DESIGNS:
            if self._run_mrna_secondary_structure(design["sequence"]):
                pass_count += 1
        pass_rate = pass_count / len(SUCCESSFUL_DESIGNS)
        print(f"\nmRNASecondaryStructure pass rate: {pass_rate:.1%}")

    def test_design_count(self):
        """Verify we have at least 15 successful designs."""
        assert len(SUCCESSFUL_DESIGNS) >= 15, (
            f"Need at least 15 successful designs, got {len(SUCCESSFUL_DESIGNS)}"
        )

    def test_all_sequences_uppercase(self):
        """All sequences should be uppercase DNA."""
        for design in SUCCESSFUL_DESIGNS:
            seq = design["sequence"]
            assert seq == seq.upper(), f"{design['name']}: sequence not uppercase"
            assert all(c in "ACGT" for c in seq), (
                f"{design['name']}: sequence contains non-ACGT characters"
            )

    def test_all_sequences_translate_cleanly(self):
        """All sequences should translate to valid protein sequences."""
        for design in SUCCESSFUL_DESIGNS:
            seq = design["sequence"]
            protein = _translate(seq)
            assert len(protein) > 0, f"{design['name']}: empty translation"
            assert all(c in "ACDEFGHIKLMNPQRSTVWY" for c in protein), (
                f"{design['name']}: translation contains invalid amino acids: "
                f"{[c for c in protein if c not in 'ACDEFGHIKLMNPQRSTVWY']}"
            )
